import{_ as e,c as r,o,ag as s}from"./chunks/framework.DPDPlp3K.js";const m=JSON.parse('{"title":"Git の操作の実体","description":"","frontmatter":{},"headers":[],"relativePath":"text/chapter-1/git-commands.md","filePath":"text/chapter-1/git-commands.md"}'),l={name:"text/chapter-1/git-commands.md"};function n(d,t,a,i,c,p){return o(),r("div",null,t[0]||(t[0]=[s('<h1 id="git-の操作の実体" tabindex="-1">Git の操作の実体 <a class="header-anchor" href="#git-の操作の実体" aria-label="Permalink to &quot;Git の操作の実体&quot;">​</a></h1><p>この章では、前編で行ってきた VSCode 上のボタン操作の裏でどんな処理がなされていたのかを解説し <code>fetch</code> や <code>pull</code> といったコマンドとの関係性を明らかにします。</p><p>大抵の開発ではこれらの操作の細かい意味合いはあまり強く意識されず、それを深く理解していなくても Git を開発に役立てることは十分に可能です。とはいえ、これらは Git の最も基本的な操作とされていて、その役割を把握していなければ解決が難しい問題に遭遇することも稀ではないので、以降の内容をなんとなくでも把握しておくことをおすすめします。</p><h2 id="ブランチ内での操作" tabindex="-1">ブランチ内での操作 <a class="header-anchor" href="#ブランチ内での操作" aria-label="Permalink to &quot;ブランチ内での操作&quot;">​</a></h2><p>以下の図は 1 本のブランチ（ここでは main という名前のブランチ）に関する操作の一覧です。</p><p><img src="https://md.trap.jp/uploads/upload_20ec43238b38dfef06c692b80c4469fa.png" alt=""></p><p>全体が同期するので 1 本と見なすことが一般的ですが、実際には</p><ul><li><strong>リモートブランチ</strong></li><li><strong>リモート追跡ブランチ</strong></li><li><strong>作業ブランチ</strong></li></ul><p>の 3 本が束になっています。リモートブランチは Gitea のサーバー上にあり、他の 2 本はローカル（お使いのデバイスの中）にあります。</p><div class="tip custom-block"><p class="custom-block-title">リモート追跡ブランチはブランチではない</p><p>紛らわしいですが、厳密にはリモート追跡ブランチはブランチではありません。リモート追跡ブランチは「リモートブランチのスナップショット」に過ぎず、<code>fetch</code> 以外の更新操作を受け付けません。ローカル環境におけるリモートブランチの代役という認識でよいと思います。</p></div><p>上図における各操作の意味は以下の通りです。</p><table style="width:100%;border-collapse:collapse;"><tr><th style="width:auto;text-align:center;">操作</th><th style="width:100%;">意味</th></tr><tr><td style="text-align:center;"><strong>clone</strong></td><td>リモートからコピーして、ローカルにリモート追跡ブランチと作業ブランチを用意する</td></tr><tr><td style="text-align:center;"><strong>fetch</strong></td><td>リモート追跡ブランチを現在のリモートブランチと同じ状態にする</td></tr><tr><td style="text-align:center;"><strong>merge</strong></td><td>リモート追跡ブランチの変更を作業ブランチに反映する</td></tr><tr><td style="text-align:center;"><strong>commit</strong></td><td>作業ブランチに変更を加えること</td></tr><tr><td style="text-align:center;"><strong>pull</strong></td><td>fetch + merge</td></tr><tr><td style="text-align:center;"><strong>push</strong></td><td>作業ブランチの変更をリモートブランチに反映する</td></tr></table><p>前編でターミナル及び VSCode 上で行った操作との対応は以下のようになります。</p><table style="width:100%;border-collapse:collapse;"><tr><th style="width:100%;">操作</th><th style="width:auto;text-align:center;text-wrap:nowrap;">Git コマンド</th></tr><tr><td>コマンド <code>git clone {リポジトリの URL}</code> の実行</td><td style="text-align:center;"><strong>clone</strong></td></tr><tr><td>デスクトップの mydrive で README.md を編集して「コミット」ボタンを押す</td><td style="text-align:center;"><strong>commit</strong></td></tr><tr><td>デスクトップの mydrive で「変更を同期 ↑1」ボタンを押す</td><td style="text-align:center;"><strong>push</strong></td></tr><tr><td>ダウンロードの mydrive で「変更の同期 ↓1」ボタンを押す</td><td style="text-align:center;"><strong>pull</strong></td></tr></table><div class="info custom-block"><p class="custom-block-title">コミット ≠ ファイルの編集</p><p>commit の説明として「作業ブランチに変更を加えること」と書きましたが、上記の対応から分かるように、ただ単に作業ディレクトリのファイルの内容を編集するだけでは commit にはなりません。ファイルの変更をステージし、明示的にコミットして初めてブランチが伸びます。</p></div><p>日頃の開発で「ブランチにコミットする」という言葉を聞いたら、通常は以下の一連の操作を指すと思ってよいでしょう。</p><ol><li>開発途中のブランチの最新状態をリモートから pull してくる</li><li>ファイルの中身を変更し、作業ブランチに commit する</li><li>作業ブランチの変更を push してリモートブランチに反映させる</li></ol><p>1 と 3 は結局のところ「リモートとローカルを同期する」ための操作です。「ブランチへのコミット」という操作は「<strong>同期</strong> → <strong>作業ブランチへのコミット</strong> → <strong>同期</strong>」という 3 段階によってリモートとローカルの両方に同じ変更を加えることを意味しています。</p><div class="tip custom-block"><p class="custom-block-title">VSCodeの「変更の同期」ボタン</p><p>表では「変更の同期 1↑」ボタンと「変更の同期 1↓」ボタンが別物であるかのような書き方をしましたが、両方ともやっていることは同じで「<strong>pull</strong> + <strong>push</strong>」をしている、と統一して考えることもできます。リモートブランチに変更がなければ <strong>pull</strong> をしても何も起こらず、逆に作業ブランチに変更がなければ <strong>push</strong> をしても何も起こらないからです。</p></div>',19)]))}const h=e(l,[["render",n]]);export{m as __pageData,h as default};
